import sys
from collections import deque
from typing import Optional, List

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def levelOrder(self, root: Optional[TreeNode]) -> List[List[int]]:
        if not root:
            return []
        result = []
        queue = deque([root])
        while queue:
            level = []
            for _ in range(len(queue)):
                node = queue.popleft()
                level.append(node.val)
                if node.left:
                    queue.append(node.left)
                if node.right:
                    queue.append(node.right)
            result.append(level)
        return result

if __name__ == '__main__':
    it = iter(sys.stdin.read().splitlines())
    try:
        n = int(next(it))
        root = None
        nodes = []
        for _ in range(n):
            val = int(next(it))
            node = TreeNode(val)
            nodes.append(node)
        for i in range(n):
            node = nodes[i]
            left_child_idx = 2 * i + 1
            right_child_idx = 2 * i + 2
            if left_child_idx < n:
                node.left = nodes[left_child_idx]
            if right_child_idx < n:
                node.right = nodes[right_child_idx]
        root = nodes[0]
        sol = Solution()
        ans = sol.levelOrder(root)
        print(len(ans))
        for level in ans:
            print(len(level), *level)
    except StopIteration:
        sys.exit(0)

