#include <numeric>
#include <iostream>
#include <vector>
#include <queue>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    vector<vector<int>> levelOrder(TreeNode* root) {
        if (!root) return {};
        vector<vector<int>> result;
        queue<TreeNode*> q;
        q.push(root);
        while (!q.empty()) {
            vector<int> level;
            int size = q.size();
            for (int i = 0; i < size; i++) {
                TreeNode* node = q.front(); q.pop();
                level.push_back(node->val);
                if (node->left) q.push(node->left);
                if (node->right) q.push(node->right);
            }
            result.push_back(level);
        }
        return result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    TreeNode* root = nullptr;
    vector<TreeNode*> nodes(n);
    for (int i = 0; i < n; i++) {
        int val;
        cin >> val;
        nodes[i] = new TreeNode(val);
    }
    for (int i = 0; i < n; i++) {
        TreeNode* node = nodes[i];
        int left_child_idx = 2 * i + 1;
        int right_child_idx = 2 * i + 2;
        if (left_child_idx < n) node->left = nodes[left_child_idx];
        if (right_child_idx < n) node->right = nodes[right_child_idx];
    }
    root = nodes[0];
    Solution sol;
    vector<vector<int>> ans = sol.levelOrder(root);
    cout << ans.size() << '\n';
    for (const auto& level : ans) {
        cout << level.size() << ' ';
        for (int val : level) cout << val << ' ';
        cout << '\n';
    }
    return 0;
}
